INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '63eb9a50-4d3e-4694-8b19-1c277936bc2e',
  '00000000-0000-0000-0000-000000000001',
  $escape$esbuild Tree Shaking — Side Effects, Pure Annotations, and Dead Code Elimination$escape$,
  $escape$esbuild tree-shakes ESM bundles by default — unused exports are dropped during bundling, not as a separate pass. The critical lever is side-effect analysis. If esbuild can't prove a module import is side-effect-free, it keeps the entire module even if nothing is consumed from it.

Two mechanisms control this. First, `sideEffects: false` in a package's `package.json` tells esbuild the package performs no top-level side effects, making entire files eligible for removal when their exports go unused. Without it, a barrel file like `export * from './utils'` forces retention of every re-export, even unused ones.

Second, the `pure` API option (or the inline `/* @__PURE__ */` comment) marks specific function calls as safe to eliminate when their return value is unused. This is essential for class factories and decorator wrappers that esbuild would otherwise conservatively retain.

esbuild's tree shaking only works on ESM source. CommonJS modules are opaque — esbuild cannot statically analyze `require()` call sites, so CJS imports are never tree-shaken. Confirm your entry points and dependencies output ESM to unlock dead code elimination.$escape$,
  $escape$import * as esbuild from 'esbuild';

await esbuild.build({
  entryPoints: ['src/index.ts'],
  bundle: true,
  format: 'esm',
  treeShaking: true,
  // Mark these calls as side-effect-free;
  // dropped when their return value is unused
  pure: ['console.log', 'createLogger', 'React.createElement'],
  outfile: 'dist/out.js',
});

// In source: annotate individual call sites inline
const logger = /* @__PURE__ */ createLogger('app');$escape$,
  $escape$javascript$escape$,
