INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c7c24ce4-e413-4d28-b36b-b869c8b552a1',
  '00000000-0000-0000-0000-000000000001',
  $escape$esbuild Bundle Analysis — Visualizing Size, Finding Bloat, and Enforcing Size Budgets in CI$escape$,
  $escape$esbuild's `--metafile` flag emits a JSON artifact containing every module's byte size, import graph, and chunk membership. Feed that file into `esbuild.analyzeMetafile()` to get a tree-printed breakdown in your terminal, or pipe it to the official bundle visualizer at esbuild.github.io/analyze for an interactive treemap. To catch bloat automatically, read the metafile in your build script and assert against `outputs[file].bytes`. If any output chunk exceeds your budget, exit with a non-zero code — CI fails, the PR is blocked.

The metafile also exposes `inputs`, letting you trace exactly which source files contribute to a given output. This is invaluable for diagnosing why a utility-only import like `lodash-es` ballooned a chunk: follow the `imports` array to find the transitive culprit. Pair `--bundle --splitting --chunk-names=[hash]` with per-chunk budgets to enforce granular limits on lazy-loaded routes, not just the total bundle.$escape$,
  $escape$import * as esbuild from 'esbuild';
import { readFileSync } from 'fs';

const result = await esbuild.build({
  entryPoints: ['src/index.ts'],
  bundle: true,
  splitting: true,
  format: 'esm',
  outdir: 'dist',
  metafile: true,
});

// Human-readable treemap in terminal
console.log(await esbuild.analyzeMetafile(result.metafile, { verbose: true }));

// CI size budget: fail if any output chunk > 150 KB
const BUDGET_BYTES = 150 * 1024;
for (const [file, { bytes }] of Object.entries(result.metafile.outputs)) {
  if (bytes > BUDGET_BYTES) {
    console.error(`Budget exceeded: ${file} is ${(bytes / 1024).toFixed(1)} KB`);
    process.exit(1);
  }
}$escape$,
