INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4a8e28bb-a9c9-430d-9b80-94f36fb2b6ec',
  '00000000-0000-0000-0000-000000000001',
  $escape$esbuild Environment Variables — define, .env Files, and Build-Time vs Runtime$escape$,
  $escape$esbuild has no built-in .env loader. Unlike Vite or webpack, it won't auto-inject process.env from a .env file — you wire it manually using the define option, which performs a textual find-and-replace at bundle time, not runtime. That distinction matters: define substitutions are inlined as literals before any JS executes, so dead-code elimination kicks in. Set NODE_ENV to 'production' and esbuild will tree-shake every if (process.env.NODE_ENV === 'development') branch out of the bundle entirely. To load .env values, use dotenv to parse the file and spread the result into define, prefixing each key with 'process.env.'. Never pass secrets this way — define values are visible in the output bundle. For values that must stay server-side, keep them out of esbuild's input entirely. For browser targets, esbuild doesn't shim process.env automatically; if you see ReferenceError: process is not defined, add 'process.env.NODE_ENV': JSON.stringify('production') explicitly or inject a global shim via inject.$escape$,
  $escape$import * as esbuild from 'esbuild';
import * as dotenv from 'dotenv';

const env = dotenv.config().parsed ?? {};

// Only expose keys prefixed with PUBLIC_ to the bundle
const defines = Object.fromEntries(
  Object.entries(env)
    .filter(([k]) => k.startsWith('PUBLIC_'))
    .map(([k, v]) => [`process.env.${k}`, JSON.stringify(v)])
);

await esbuild.build({
  entryPoints: ['src/index.ts'],
  bundle: true,
  platform: 'browser',
  define: {
    'process.env.NODE_ENV': JSON.stringify(process.env.NODE_ENV ?? 'development'),
    ...defines,
  },
  outfile: 'dist/bundle.js',
});$escape$,
  $escape$typescript$escape$,
