INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'edb61473-5528-4da4-8695-f196003154b9',
  '00000000-0000-0000-0000-000000000001',
  $escape$esbuild TypeScript — Transpile-Only vs Type-Check, Speed vs Safety$escape$,
  $escape$esbuild strips TypeScript types without running tsc — it never type-checks. That's why `esbuild src/index.ts --bundle --outfile=dist/out.js` finishes in milliseconds regardless of codebase size. esbuild treats TypeScript as syntactic sugar: it parses, removes annotations, and emits JavaScript. Type errors are invisible to it.

This is intentional. During development, the feedback loop is fast. In CI, you run `tsc --noEmit` separately as a pure type-check pass — no output files, just diagnostics. The two tools do different jobs.

The risk: esbuild will happily emit JavaScript from code that tsc would reject. A mistyped function signature, a missing property, an impossible cast — all become runtime bugs. If you skip `tsc --noEmit` in your pipeline, you have no safety net.

The pattern that works: use esbuild for all emit (dev server, production bundle) and tsc exclusively for type validation. Wire both into your CI job. Never rely on esbuild's output as proof of type correctness — it has no opinion on that.$escape$,
  $escape$// package.json scripts — separation of concerns
{
  "scripts": {
    "build": "esbuild src/index.ts --bundle --outfile=dist/out.js --platform=node",
    "typecheck": "tsc --noEmit",
    "ci": "npm run typecheck && npm run build"
  }
}

// esbuild JavaScript API — same principle
import { build } from 'esbuild';

await build({
  entryPoints: ['src/index.ts'],
  bundle: true,
  outfile: 'dist/out.js',
  // No type-checking happens here — run tsc --noEmit separately
});$escape$,
  $escape$javascript$escape$,
