INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2855f8d9-4fe0-40db-b55f-a61b8a9e9320',
  '00000000-0000-0000-0000-000000000001',
  $escape$esbuild Production Optimization — Minification, Tree-Shaking, and Brotli in One Pass$escape$,
  $escape$esbuild's `minify: true` is shorthand for three distinct passes: `minifyWhitespace` strips comments and formatting, `minifyIdentifiers` renames local variables to single characters, and `minifySyntax` collapses constant expressions and simplifies control flow. Use them individually in development for targeted profiling, together in production.

Tree-shaking is automatic for ESM (`format: 'esm'`), but you can force it on CommonJS output with `treeShaking: true`. Mark library packages with `"sideEffects": false` in their `package.json` to let esbuild drop unused exports aggressively — without it, esbuild conservatively retains entire modules.

esbuild has no built-in gzip/brotli writer, but setting `write: false` captures `outputFiles` as `Uint8Array` buffers in memory. Pipe them through Node's `zlib.gzipSync` and `zlib.brotliCompressSync` to write compressed variants alongside the originals. Enable `metafile: true` and call `esbuild.analyzeMetafile()` to verify dead-code removal is actually working — unexpectedly large chunks almost always trace back to a missing `sideEffects` annotation or a dynamic `require()` call defeating static analysis.$escape$,
  $escape$import * as esbuild from 'esbuild';
import { gzipSync, brotliCompressSync } from 'zlib';
import { writeFileSync } from 'fs';

const result = await esbuild.build({
  entryPoints: ['src/index.ts'],
  bundle: true,
  format: 'esm',
  minify: true,        // minifyWhitespace + minifyIdentifiers + minifySyntax
  treeShaking: true,
  metafile: true,
  write: false,        // capture buffers in memory
});

for (const file of result.outputFiles) {
  writeFileSync(file.path, file.contents);
  writeFileSync(`${file.path}.gz`, gzipSync(file.contents, { level: 9 }));
  writeFileSync(`${file.path}.br`, brotliCompressSync(file.contents));
}

console.log(await esbuild.analyzeMetafile(result.metafile));$escape$,
  $escape$javascript$escape$,
