INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a9abb1c7-80eb-42ce-9b6b-a6afa4cebfcd',
  '00000000-0000-0000-0000-000000000001',
  $escape$esbuild Plugin System — Intercepting the Build Pipeline with Hooks$escape$,
  $escape$esbuild's plugin API exposes two primary hooks: `onResolve` and `onLoad`. Every plugin is an object with a `name` and a `setup(build)` function — that's the entire contract.

`onResolve` intercepts module resolution. You match against an import path using a `filter` regex and optionally a `namespace`, then return a custom `path` and `namespace`. This lets you redirect imports to virtual modules or alternative file paths without touching disk.

`onLoad` intercepts file reading. Match by namespace (and optionally path), then return `contents` and a `loader` (`js`, `ts`, `css`, `json`, etc.). esbuild skips the filesystem entirely and uses what you return.

The `filter` regex runs in Go — keep it simple and avoid lookaheads. Plugins run sequentially; the first matching hook wins. Use `build.onStart` and `build.onEnd` for lifecycle work like cache invalidation or writing manifests.

All hooks are async-capable: return a Promise and esbuild awaits it. Plugins compose cleanly — pass them as an array to `plugins` in your `BuildOptions`.$escape$,
  $escape$import * as esbuild from 'esbuild';

const virtualPlugin: esbuild.Plugin = {
  name: 'virtual-env',
  setup(build) {
    build.onResolve({ filter: /^env$/ }, () => ({
      path: 'env',
      namespace: 'virtual-env-ns',
    }));

    build.onLoad({ filter: /.*/, namespace: 'virtual-env-ns' }, () => ({
      contents: `export const MODE = '${process.env.NODE_ENV}';`,
      loader: 'js',
    }));
  },
};

await esbuild.build({
  entryPoints: ['src/index.ts'],
  bundle: true,
  plugins: [virtualPlugin],
  outfile: 'dist/out.js',
});$escape$,
