INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3bf28c9b-5fcd-484c-acd4-d776c4fce0b0',
  '00000000-0000-0000-0000-000000000001',
  $escape$esbuild's Take on Webpack Loaders, Plugins, and the Module Federation Gap$escape$,
  $escape$esbuild draws a hard line between loaders and plugins—Webpack blurs it. Loaders in esbuild are built-in, Go-native file-type handlers declared in the build options: `{ '.svg': 'text', '.png': 'dataurl', '.wasm': 'binary' }`. They run at near-zero cost because they never leave the Go runtime. That's your Webpack `file-loader`, `url-loader`, and `raw-loader` collapsed into a single config key.

Plugins fill the gap when builtins can't. The plugin API exposes two hooks: `onResolve` (intercept module resolution) and `onLoad` (transform file content). An `onLoad` callback returning `{ contents, loader: 'jsx' }` is the direct equivalent of a Webpack loader chain—but without chaining. In esbuild, the first `onLoad` that matches a filter wins; there's no pipe.

Module federation is where esbuild hits a wall. There is no `ModuleFederationPlugin` counterpart. The pragmatic escape hatch: expose micro-frontend remotes as self-contained ESM bundles served from a CDN, then consume them at runtime with dynamic `import('https://remote/entry.js')`. This trades build-time federation for runtime composition—esbuild builds each remote independently, no shared plugin contract required.$escape$,
  $escape$import * as esbuild from 'esbuild';

const svgPlugin: esbuild.Plugin = {
  name: 'svg-react',
  setup(build) {
    build.onLoad({ filter: /\.svg$/ }, async ({ path }) => {
      const svg = await Bun.file(path).text();
      return {
        contents: `export default () => (${svg});`,
        loader: 'jsx',
      };
    });
  },
};

await esbuild.build({
  entryPoints: ['src/index.tsx'],
  bundle: true,
  loader: { '.png': 'dataurl', '.wasm': 'binary' },
  plugins: [svgPlugin],
  outdir: 'dist',
});$escape$,
