INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b2fc189d-6a8f-4233-a426-e2626d30bbc7',
  '00000000-0000-0000-0000-000000000001',
  $escape$esbuild Config Sharing — Base Configs, Overrides, and CI Caching That Actually Works$escape$,
  $escape$esbuild has no built-in config file format — your config is just a JS/TS module exporting a `BuildOptions` object. That's your sharing primitive. Define a `base.config.ts` that exports a `BuildOptions`, then spread it per environment: `{ ...baseConfig, minify: true, sourcemap: false }` for prod, `{ ...baseConfig, sourcemap: 'inline' }` for dev. For monorepos, publish the base as a local package or use a path alias — esbuild doesn't care, it's just an import.

For CI caching, esbuild's cache lives in the OS temp dir by default and isn't portable. The real win is caching your `node_modules` (esbuild's native binary lives there) and using `--metafile` output to detect what actually changed. Pair `--metafile=meta.json` with a script that diffs input hashes between runs — skip rebuilds entirely for unchanged entry points. esbuild's incremental builds (`incremental: true` + `rebuild()`) persist in-process only, so they're useless in CI. Lean on artifact caching (`actions/cache` keyed on lockfile hash) and split entry points so only dirty chunks rebuild.$escape$,
  $escape$// base.config.ts
import type { BuildOptions } from 'esbuild';

export const baseConfig: BuildOptions = {
  bundle: true,
  platform: 'browser',
  target: ['es2020'],
  loader: { '.svg': 'dataurl', '.png': 'file' },
  metafile: true,
};

// prod.config.ts
import { build } from 'esbuild';
import { baseConfig } from './base.config';

await build({
  ...baseConfig,
  entryPoints: ['src/index.ts'],
  outdir: 'dist',
  minify: true,
  sourcemap: false,
});$escape$,
  $escape$typescript$escape$,
